+fn truncate_path_label(path: &str, max_chars: usize) -> String {
+    if max_chars == 0 {
+        return String::new();
+    }
+    if path.chars().count() <= max_chars {
+        return path.to_string();
+    }
+    if max_chars == 1 {
+        return "…".to_string();
+    }
+    let tail: String = path.chars().rev().take(max_chars - 1).collect();
+    let tail: String = tail.chars().rev().collect();
+    format!("…{tail}")
+}
